int solveQuery ( int start , int end , const std::vector<int>& arr ) {
    // In C++, std::map<KeyType, ValueType> is a common way to implement a dictionary or hash map.
    // Here, keys are array elements (int) and values are their frequencies (int).
    std::map<int, int> frequency;
    // Iterate through the specified range [start, end] inclusively.
    // This translates `for i in range(start, end + 1)` from Python.
    for ( int i = start ; i <= end ; ++i ) {
        // Accessing map[key] will automatically insert the key with a default-constructed value (0 for int)
        // if it doesn't exist. Then, the value is incremented.
        // This compactly handles both `if key in dict: dict[key] += 1` and `else: dict[key] = 1`.
        frequency[ arr[i] ]++;
    }
    int count = 0;
    // Iterate through the key-value pairs in the frequency map.
    // `const auto& pair` means each element `pair` is a constant reference to a `std::pair<const int, int>`.
    // `pair.first` is the key (equivalent to `x` in Python's `for x in frequency:`).
    // `pair.second` is the value (equivalent to `frequency[x]` in Python).
    for ( const auto& pair : frequency ) {
        // Check if the key is equal to its corresponding frequency (value).
        if ( pair.first == pair.second ) {
            count++;
        }
    }
    return count;
}

