// Function to perform binary search recursively
// arr: The sorted array (vector) to search in. Passed by const reference for efficiency.
// l: The lower bound index of the current search space.
// r: The upper bound index of the current search space.
// x: The value to search for.
// Returns the index of x if found, otherwise -1.
int binarySearch(const std::vector<int>& arr, int l, int r, int x) {
    // Base case: If the search space is valid (l <= r)
    if (r >= l) {
        // Calculate the middle index.
        // Using l + (r - l) / 2 prevents potential overflow that (l + r) / 2 might cause
        // if l and r are very large integers whose sum exceeds INT_MAX.
        int mid = l + (r - l) / 2;
        // If the element at mid is x, we found it
        if (arr[mid] == x) {
            return mid;
        }
        // If x is smaller than the element at mid, search in the left half
        else if (arr[mid] > x) {
            return binarySearch(arr, l, mid - 1, x);
        }
        // If x is larger than the element at mid, search in the right half
        else { // arr[mid] < x
            return binarySearch(arr, mid + 1, r, x);
        }
    }
    // Base case: If the search space is invalid (l > r), element not found
    else {
        return -1;
    }
}

