// Function to calculate the minimum number of trials in the worst case
// for n eggs and k floors.
int eggDrop(int n, int k) {
    // Create a 2D vector (dynamic array) to store results of subproblems.
    // eggFloor[i][j] will store the minimum trials needed for i eggs and j floors.
    std::vector<std::vector<int>> eggFloor(n + 1, std::vector<int>(k + 1, 0));
    // Base cases:
    // If we have 1 egg or 0 floors:
    // For 0 floors, 0 trials are needed.
    // For 1 floor, 1 trial is needed.
    // For 0 eggs, 0 trials are needed (this case is implicit in the loop bounds
    // or handled by eggFloor[i][0] = 0).
    // Fill base cases for 0 or 1 floor for any number of eggs:
    for (int i = 1; i <= n; ++i) {
        eggFloor[i][1] = 1; // 1 trial needed for 1 floor
        eggFloor[i][0] = 0; // 0 trials needed for 0 floors
    }
    // Fill base cases for 1 egg and any number of floors:
    // With 1 egg, in the worst case, we have to try each floor from 1 to j.
    for (int j = 1; j <= k; ++j) {
        eggFloor[1][j] = j;
