    // Fill the DP table for more than 1 egg and more than 1 floor
    for (int i = 2; i <= n; ++i) {   // i represents number of eggs
        for (int j = 2; j <= k; ++j) { // j represents number of floors
            eggFloor[i][j] = INT_MAX; // Initialize with a very large value
            // Consider dropping an egg from each floor x (from 1 to j)
            for (int x = 1; x <= j; ++x) {
                // If the egg breaks (eggFloor[i - 1][x - 1]):
                // We have i-1 eggs left and need to check floors below x (x-1 floors).
                // If the egg doesn't break (eggFloor[i][j - x]):
                // We have i eggs left and need to check floors above x (j-x floors).
                // We take the maximum of these two worst-case scenarios,
                // and add 1 for the current drop.
                int res = 1 + std::max(eggFloor[i - 1][x - 1], eggFloor[i][j - x]);
                // Update eggFloor[i][j] with the minimum of all possible x values
                if (res < eggFloor[i][j]) {
                    eggFloor[i][j] = res;
                }
            }
        }
    }
    // The result is stored in eggFloor[n][k]
    return eggFloor[n][k];
}

