// Function to find the minimum number of insertions to make a substring a palindrome
// str: The input string
// l: The starting index of the substring
// h: The ending index of the substring
int findMinInsertions(const std::string& str, int l, int h) {
    // Base Case 1: If the low index is greater than the high index,
    // it means an empty or invalid range. This is equivalent to sys.maxsize
    // in Python to indicate an unreachable or invalid state that should not be chosen
    // by min operations.
    if (l > h) {
        return std::numeric_limits<int>::max();
    }
    // Base Case 2: If there is only one character, it's already a palindrome.
    // No insertions needed.
    if (l == h) {
        return 0;
    }
    // Base Case 3: If there are two characters.
    // If they are the same, 0 insertions needed.
    // If they are different, 1 insertion needed (e.g., "ab" -> "aba" or "bab").
    if (l == h - 1) {
        return (str[l] == str[h]) ? 0 : 1;
    }
    // Recursive Step:
    // If the first and last characters of the current substring match,
    // they don't need any insertions. We only need to solve for the inner substring.
    if (str[l] == str[h]) {
        return findMinInsertions(str, l + 1, h - 1);
    }
    // If the first and last characters do not match, we have two options:
    // 1. Insert the character `str[h]` at the beginning of the substring
    //    (or conceptually, make `str[l]` match `str[h]`) and solve for `str[l...h-1]`.
    // 2. Insert the character `str[l]` at the end of the substring
    //    (or conceptually, make `str[h]` match `str[l]`) and solve for `str[l+1...h]`.
    // We take the minimum of these two options and add 1 for the insertion we made.
    else {
        return (std::min(findMinInsertions(str, l, h - 1),
                         findMinInsertions(str, l + 1, h)) + 1);
