            F[i][i] = 1;
        } else {
            F[i][i] = 0;
        }
        if (symb[i] == 'T') {
            T[i][i] = 1;
        } else {
            T[i][i] = 0;
        }
    }
    // Fill the table in a bottom-up manner
    // gap represents the length of the subexpression minus 1
    for (int gap = 1; gap < n; ++gap) {
        // i is the starting index of the subexpression
