long long countFriendsPairings(int n) {
    // Create a DP table of size n + 1.
    // Use long long to store the results, as the number of pairings can grow very large
    // and might exceed the capacity of an int.
    std::vector<long long> dp(n + 1);
    // Fill the DP table iteratively
    for (int i = 0; i <= n; ++i) {
        // Base cases:
        // dp[0] = 0 (no friends, 0 ways to pair)
        // dp[1] = 1 (one friend, can only stay single)
        // dp[2] = 2 (two friends, they can either both stay single, or they can pair up)
        if (i <= 2) {
            dp[i] = i;
        } else {
            // Recurrence relation:
            // For 'i' friends, there are two possibilities for the i-th friend:
            // 1. The i-th friend remains single:
            //    In this case, the remaining (i - 1) friends can be paired in dp[i - 1] ways.
            // 2. The i-th friend pairs up with one of the other (i - 1) friends:
            //    There are (i - 1) choices for the i-th friend's partner.
            //    Once paired, the remaining (i - 2) friends can be paired in dp[i - 2] ways.
            //    So, this contributes (i - 1) * dp[i - 2] ways.
            //
            // We cast (i - 1) to long long before multiplication to ensure the
            // intermediate product is computed using long long arithmetic, preventing overflow.
            dp[i] = dp[i - 1] + (long long)(i - 1) * dp[i - 2];
        }
    }
    // The result for 'n' friends is stored at dp[n]
    return dp[n];
}

