// Function to check if a given matrix is an identity matrix.
// An identity matrix has 1s on the main diagonal and 0s elsewhere.
//
// Parameters:
//   mat: A constant reference to a 2D vector representing the matrix.
//        It's passed by const reference to avoid copying and ensure
//        the original matrix is not modified.
//   N:   The dimension of the square matrix (N x N).
//
// Returns:
//   true if the matrix is an identity matrix, false otherwise.
bool isIdentity(const std::vector<std::vector<int>>& mat, int N) {
    // Iterate through each row of the matrix
    for (int row = 0; row < N; ++row) {
        // Iterate through each column in the current row
        for (int col = 0; col < N; ++col) {
            // Check elements on the main diagonal (where row index equals col index)
            if (row == col) {
                // For an identity matrix, diagonal elements must be 1.
                if (mat[row][col] != 1) {
                    return false; // Found a non-1 diagonal element, so it's not an identity matrix.
                }
            }
            // Check elements off the main diagonal (where row index is not equal to col index)
            else { // row != col
                // For an identity matrix, off-diagonal elements must be 0.
                if (mat[row][col] != 0) {
                    return false; // Found a non-0 off-diagonal element, so it's not an identity matrix.
                }
            }
        }
    }
    // If the loops complete without returning false, it means all elements
    // satisfy the conditions for an identity matrix.
    return true;
}

