    // possible divisors up to sqrt(n) without finding any.
    // Therefore, n must be prime.
    if (static_cast<long long>(i) * i > n) { // Use long long for i*i to prevent potential overflow
        return true;
    }
    // Recursive step: Check the next potential divisor (i + 1).
    return isPrime(n, i + 1);
