    // Iterate through each item
    for (int i = 0; i < n; ++i) {
        // Iterate through the knapsack capacities from W down to 0.
        // We iterate backwards to ensure that for each item,
        // its contribution to dp[j] is considered only once (0/1 knapsack property),
