                // The value remains dp[j] (from previous calculations).
                // Option 2: Include the current item 'i'.
                // The value would be val[i] (value of current item)
                // plus the maximum value that can be obtained with the remaining capacity (j - wt[i]).
                // This remaining value is found in dp[j - wt[i]].
                // Take the maximum of these two options.
                dp[j] = std::max(dp[j], val[i] + dp[j - wt[i]]);
            }
        }
    }
    // After processing all items, dp[W] will contain the maximum value
    // that can be obtained with a knapsack of capacity W.
    return dp[W];
