int nearestSmallerEqFib(int n) {
    if (n == 0 || n == 1) {
        return n;
    }
    int f1 = 0;
    int f2 = 1;
    int f3 = 1; // f3 is initially F(2)
    while (f3 <= n) {
        f1 = f2;
        f2 = f3;
        f3 = f1 + f2; // Calculate the next Fibonacci number
    }
    // At this point, f3 is the first Fibonacci number greater than n.
    // f2 is the Fibonacci number immediately preceding f3,
    // which means f2 is the largest Fibonacci number less than or equal to n.
    return f2;
}
